func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const alpha = 1.0
	const beta = 0.5
	type cand struct {
		assignIdx int
		costDelta float64
		insertPos int
	}
	for jj := range oris {
		bestCand := cand{-1, 1e18, -1}
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			assignCopy := dispatch.Assigns[ai]
			if assignCopy.AddShip(total_ship+jj, oris[jj], dess[jj]) {
				assignCopy.GenRoute()
				if assignCopy.Cost >= 0 {
					delta := assignCopy.Cost - dispatch.Assigns[ai].Cost
					score := delta + beta*(cal_dis(assignCopy.StationCurrent, oris[jj])+cal_dis(oris[jj], dess[jj]))
					if score < bestCand.costDelta {
						bestCand.assignIdx = ai
						bestCand.costDelta = score
					}
				}
			}
		}
		if bestCand.assignIdx >= 0 {
			dispatch.Assigns[bestCand.assignIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestCand.assignIdx].GenRoute()
		} else {
			newAi := dispatch.AssignsLen
			if newAi < MAXASSIGNS {
				dispatch.Assigns[newAi].AddShip(total_ship+jj, oris[jj], dess[jj])
				dispatch.Assigns[newAi].GenRoute()
				if dispatch.Assigns[newAi].Cost >= 0 {
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

