Use a greedy best-fit insertion strategy with fallback to empty assign creation while maintaining feasibility checks across all orders.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx   int
		costInc float64
		ok     bool
	}
	for shipID := 0; shipID < len(oris); shipID++ {
		best := cand{-1, 1e100, false}
		for aIdx := 0; aIdx < MAXASSIGNS; aIdx++ {
			if aIdx >= dispatch.AssignsLen && aIdx != dispatch.AssignsLen {
				continue
			}
			tmpCost := dispatch.Assigns[aIdx].Cost
			addOk := dispatch.Assigns[aIdx].AddShip(total_ship+shipID, oris[shipID], dess[shipID])
			if addOk {
				dispatch.Assigns[aIdx].GenRoute()
				newCost := dispatch.Assigns[aIdx].Cost
				if newCost >= 0 {
					inc := newCost - tmpCost
					if inc < best.costInc {
						best.idx = aIdx
						best.costInc = inc
						best.ok = true
					}
				}
				dispatch.Assigns[aIdx].RemoveShip(total_ship + shipID)
				dispatch.Assigns[aIdx].GenRoute()
			}
		}
		targetIdx := -1
		if best.ok {
			targetIdx = best.idx
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				targetIdx = dispatch.AssignsLen
			} else {
				for i := 0; i < MAXASSIGNS; i++ {
					tmpCost := dispatch.Assigns[i].Cost
					addOk := dispatch.Assigns[i].AddShip(total_ship+shipID, oris[shipID], dess[shipID])
					if addOk {
						dispatch.Assigns[i].GenRoute()
						newCost := dispatch.Assigns[i].Cost
						if newCost >= 0 {
							targetIdx = i
							break
						}
						dispatch.Assigns[i].RemoveShip(total_ship + shipID)
						dispatch.Assigns[i].GenRoute()
					}
				}
			}
		}
		if targetIdx >= 0 {
			inserted := dispatch.Assigns[targetIdx].AddShip(total_ship+shipID, oris[shipID], dess[shipID])
			if inserted {
				dispatch.Assigns[targetIdx].GenRoute()
				if dispatch.Assigns[targetIdx].Cost < 0 {
					dispatch.Assigns[targetIdx].RemoveShip(total_ship + shipID)
					dispatch.Assigns[targetIdx].GenRoute()
				} else {
					if targetIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen++
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

